
.head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 10px 5px 10px 10px;
  border-bottom: 1px solid #E4E4E4;
  min-height: 3rem;

  .title {
    margin: 0;
    color: #002337;
    flex-grow: 0.1;
  }

  .configuration {
    color: #ACACAC;
    flex-grow: 1;
  }

  .configure-button-icon {
    color: #999999;

    &.parent-hovered {
      color: #777777;
    }

    &:hover {
      color: #002337;
    }
  }
}
