
@import "../../styles/_dependencies.scss";

.customize-modal-body {
  white-space: break-spaces;
  padding: 2rem;

  &.loading {
    user-select: none;
    opacity: .5;
  }

  ul {
    list-style: none;
    display: flex;
    flex-direction: column;
    margin: 0;
    padding: 0;

    .ghost {
      background-color: rgba(172, 172, 172, 0.28);
      opacity: .5;

      .handle {
        visibility: hidden;
      }

      .switcher {
        display: none;
      }
    }

    .chosen {
      box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px -1px rgba(0, 0, 0, 0.1);
    }

    li {
      padding: 0.75rem 0.5rem;
      font-size: 12pt;
      border-radius: .25rem;
      display: flex;
      align-items: center;

      span {
        flex-grow: 1;
        user-select: none;
      }

      i {
        &.handle {
          margin-right: 0.5rem;
          cursor: grab;
          color: #ACACAC;
        }

        &.switcher {
          cursor: pointer;

          &.fa-eye-slash {
            color: #ACACAC;
          }
        }
      }
    }
  }
}
