
.table {
  margin: 0;
  border: none;
  border-collapse: collapse;
  text-align: left;
  width: 100%;
}

thead tr th {
  white-space: nowrap;
  background: #FFFFFF;
  color: #333333;
  border: none;
  border-bottom: 3px solid #000000;
  padding: 12px;
  width: auto;

  .asc {
    background: none;
  }
}

tbody {
  > :nth-child(even) {
    background: #EFEFEF;
  }

  tr {
    border: none;

    td {
      white-space: nowrap;
      border: none;
      padding: 12px;
    }
  }
}

.row {
  margin: 0;

  &:last-child {
    display: none;
  }
}
